import{_ as e,o as t,c as o,ag as r}from"./chunks/framework.BZohXCq9.js";const d=JSON.parse('{"title":"第1集：缝不完的袍子","description":"","frontmatter":{"title":"第1集：缝不完的袍子","outline":false},"headers":[],"relativePath":"novels/jin-gu-yao/drama/01.md","filePath":"novels/jin-gu-yao/drama/01.md","lastUpdated":1774160915000}'),n={name:"novels/jin-gu-yao/drama/01.md"};function s(m,p,a,g,l,i){return t(),o("div",null,[...p[0]||(p[0]=[r('<h1 id="第-1-集-缝不完的袍子" tabindex="-1">第 1 集：缝不完的袍子 <a class="header-anchor" href="#第-1-集-缝不完的袍子" aria-label="Permalink to &quot;第 1 集：缝不完的袍子&quot;">​</a></h1><blockquote><p>钩子类型：悬念 + 身份反转 时长：约 3 分钟</p></blockquote><hr><h2 id="【开场-·-闪前】" tabindex="-1">【开场 · 闪前】 <a class="header-anchor" href="#【开场-·-闪前】" aria-label="Permalink to &quot;【开场 · 闪前】&quot;">​</a></h2><p><em>画面：夜色。一个穿男装的清瘦身影站在门口，背对镜头。远处是黑沉沉的长安城。</em></p><p><strong>三娘（画外音）</strong>：大业十三年，我缝完了丈夫最后一件袍子。然后决定去造反。</p><p><em>她转身。灯光照亮半张脸——冷静、笃定。</em></p><p><strong>三娘</strong>：三宝，明天起，叫我李公子。</p><p><em>【黑屏。打出字幕：三天前。】</em></p><hr><h2 id="【正片开始】" tabindex="-1">【正片开始】 <a class="header-anchor" href="#【正片开始】" aria-label="Permalink to &quot;【正片开始】&quot;">​</a></h2><p><strong>场景：柴府院子，傍晚</strong></p><p><em>三娘坐在廊下缝袍子。阳光懒洋洋的。</em></p><p><em>远处两个孩子在打架——</em></p><p><strong>柴令武</strong>（3岁，嚎叫）：娘——！哥哥又抢我的木马！</p><p><strong>柴哲威</strong>（5岁，面不改色）：我没抢。它自己断的。</p><p><strong>柴令武</strong>：你拽断的！</p><p><strong>柴哲威</strong>：它本来就要断了。</p><p><em>三娘头也不抬。</em></p><p><strong>三娘</strong>：哲威，把马还给弟弟。</p><p><em>柴哲威一脸不情愿地把半截木马塞给弟弟。柴令武接过去，看了看——愣了三秒，嚎啕大哭。</em></p><p><em>马三宝从厨房探出头来。</em></p><p><strong>马三宝</strong>：怎么了怎么了？</p><p><strong>三娘</strong>：木马断了。</p><p><strong>马三宝</strong>（精准判断）：大公子干的？</p><p><em>柴哲威踢蚂蚁的脚顿了一下。</em></p><p><strong>三娘</strong>：三宝，找块木头，给令武削一个新的。</p><p><strong>马三宝</strong>：夫人，上次那个您说像老鼠……</p><p><strong>三娘</strong>：那这次削好看点。</p><p><strong>马三宝</strong>（苦脸）：……我尽量。</p><p><em>厨房传来翻箱倒柜的声音，然后一声闷响。</em></p><p><strong>马三宝</strong>（画外）：哎哟——</p><p><em>三娘摇头，叹口气，低头继续缝袍子。</em></p><p><em>缝了两针，嘴角忍不住弯了一下。</em></p><p><strong>三娘（画外音）</strong>：这件袍子，去年秋天柴绍猎鹿时剐的。搁了大半年了，不是没时间缝——是每次拿起来就想到他。</p><hr><h2 id="【插入-快速闪回】" tabindex="-1">【插入：快速闪回】 <a class="header-anchor" href="#【插入-快速闪回】" aria-label="Permalink to &quot;【插入：快速闪回】&quot;">​</a></h2><p><em>画面闪过：柴绍满身是泥，兴高采烈把一只瘸腿兔子放到三娘面前。</em></p><p><strong>柴绍</strong>：三娘你看！</p><p><strong>三娘</strong>：你去猎鹿，猎回来一只兔子。兔子还是瘸的。</p><p><strong>柴绍</strong>（不以为意）：鹿跑了，但这兔子肥啊！</p><p><em>闪回结束。</em></p><hr><h2 id="【回到院子】" tabindex="-1">【回到院子】 <a class="header-anchor" href="#【回到院子】" aria-label="Permalink to &quot;【回到院子】&quot;">​</a></h2><p><em>院子里恢复了平静。小的趴在三娘腿上睡着了，鼻涕泡一鼓一鼓。大的在院子里用竹竿&quot;杀敌&quot;，把槐花打了一地。</em></p><p><em>门响。</em></p><p><em>三娘以为是马三宝，没抬头。</em></p><p><strong>柴绍</strong>（低声）：三娘。</p><p><em>三娘手指一顿。她抬起头——</em></p><p><em>柴绍站在门口，当值袍服，腰间横刀没解。脸上的表情她从没见过。</em></p><p><strong>三娘（画外音）</strong>：我见过他高兴的样子、心虚的样子、紧张的样子。但这一次——像一个人同时踩到了金子和蛇。</p><p><em>柴绍的目光扫过睡着的小儿子和挥竹竿的大儿子。</em></p><p><strong>柴绍</strong>：孩子们……</p><p><em>三娘秒懂。她轻轻放下小儿子，盖好薄衫。</em></p><p><strong>三娘</strong>：哲威，去找三宝。</p><p><strong>柴哲威</strong>：我不想去，三宝削的马好丑——</p><p><strong>三娘</strong>：柴哲威。</p><p><em>五岁的柴哲威精准识别出&quot;再说一个字试试&quot;的信号，竹竿一扔，跑了。</em></p><p><em>院子安静。槐花还在落。</em></p><p><em>柴绍从怀里掏出一截竹管。</em></p><p><em>三娘看到上面的刻字——</em></p><p><em>特写：一个&quot;渊&quot;字。</em></p><p><em>三娘接过来。手指碰到柴绍的手，感觉到——他在抖。</em></p><p><em>她挑开蜡封，抽出绢帛。</em></p><p><em>镜头不给绢帛内容，只拍三娘的眼睛——看了第一遍，平静；看了第二遍，瞳孔微缩。</em></p><p><em>她把绢帛折好。</em></p><p><strong>三娘</strong>（声音平稳）：父亲要起兵。他让你去太原。</p><p><em>长停顿。</em></p><p><em>远处柴哲威的声音飘过来：</em></p><p><strong>柴哲威</strong>（远处）：三宝——你在削什么？好丑啊！</p><p><strong>马三宝</strong>（远处）：你行你来！</p><p><em>柴绍深吸一口气。</em></p><p><strong>柴绍</strong>：三娘，我得走。可是——你们留在长安……万一隋兵来查……</p><p><em>三娘看着他。灯光里，柴绍的脸一半亮一半暗。</em></p><p><strong>三娘</strong>：你走吧。</p><p><em>柴绍愣住。</em></p><p><strong>三娘</strong>：我是个妇人，带着两个孩子，谁会觉得我能翻出什么浪来？</p><p><em>她低头看了看那件缝了大半年的袍子。</em></p><p><strong>三娘</strong>：这件袍子我先不缝了。等你回来再说。</p><p><em>柴绍盯着她。</em></p><p><strong>柴绍</strong>：三娘……你是不是已经想好了？</p><p><em>三娘没回答。微微一笑。</em></p><hr><h2 id="【第-1-集钩子】" tabindex="-1">【第 1 集钩子】 <a class="header-anchor" href="#【第-1-集钩子】" aria-label="Permalink to &quot;【第 1 集钩子】&quot;">​</a></h2><p><em>画面切黑。字幕浮现：</em></p><p><strong>&quot;三娘没有告诉柴绍——这件事，她已经等了很多年。&quot;</strong></p><p><em>切回开场那个穿男装的背影。这次镜头拉远，她身后站着一小队人马。</em></p><hr><p><em>第 1 集 完</em></p>',89)])])}const u=e(n,[["render",s]]);export{d as __pageData,u as default};
